import { createRoot } from 'react-dom/client'
import './index.css'
import RetirementPlanner from './pages/RetirementPlan/RetirementPlanner.tsx';
import TaxSavingsPlanner from './pages/TaxSavingsPlan/TaxSavingsPlanner.tsx';
import SavingTools from './pages/SavingTools/SavingTools.tsx';

const rootRetirement = document.getElementById('root-retirement');
if (rootRetirement) {
  createRoot(rootRetirement).render(<RetirementPlanner />);
}

const rootTaxSaving = document.getElementById('root-tax-saving');
if (rootTaxSaving) {
  createRoot(rootTaxSaving).render(<TaxSavingsPlanner />);
}

const rootSavingTools = document.getElementById('root-saving-tools');
if (rootSavingTools) {
  createRoot(rootSavingTools).render(<SavingTools />);
}
